func (a Addon) Validate() error {
	var errs []error
	if err := a.NamespacedID.Validate(); err != nil { errs = append(errs, err) }
	if err := a.ManagedModel.Validate(); err != nil { errs = append(errs, err) }
	if err := a.AddonMeta.Validate(); err != nil { errs = append(errs, err) }
	for _, rc := range a.RateCards { if err := rc.Validate(); err != nil { errs = append(errs, err) } }
	return models.NewNillableGenericValidationError(errors.Join(errs...))
}

func (p Plan) Validate() error {
	return p.ValidateWith(ValidatePlanMeta(), ValidatePlanPhases())
}

func ValidatePlanPhases() models.ValidatorFunc[Plan] {
	return func(p Plan) error {
		var errs []error
		for _, phase := range p.Phases {
			if err := phase.Validate(); err != nil {
				errs = append(errs, fmt.Errorf("invalid plan phase %q: %s", phase.Key, err))
			}
		}
		return models.NewNillableGenericValidationError(errors.Join(errs...))
	}
}

func (a PlanAddon) Validate() error {
	var errs []error
	if err := a.NamespacedID.Validate(); err != nil { errs = append(errs, err) }
	if err := a.ManagedModel.Validate(); err != nil { errs = append(errs, err) }
	if err := a.Plan.Validate(); err != nil { errs = append(errs, err) }
	if err := a.Addon.Validate(); err != nil { errs = append(errs, err) }
	if err := a.AsProductCatalogPlanAddon().Validate(); err != nil { errs = append(errs, err) }
	return models.NewNillableGenericValidationError(errors.Join(errs...))
}

func (p *Plan) GetPhases() []subscription.PlanPhase {
	ps := make([]subscription.PlanPhase, 0, len(p.Phases))
	startAfter := datetime.ISODuration{}
	for idx, ph := range p.Phases {
		ps = append(ps, &Phase{Phase: ph, StartAfter: startAfter, Index: idx})
		startAfter, _ = startAfter.Add(lo.FromPtr(ph.Duration))
	}
	return ps
}
